// @n8n-harness:primitive — exempt from pure-function discipline
//
// No-op stub. Orphaned locks self-heal via Redis-side EXPIRE (set by INCR's
// expire+ttl params in lock_acquisition.B-16) — the lock key vanishes
// `ttl_seconds` after the original acquire, regardless of whether the holder
// crashed. Next acquire INCRs from scratch.
//
// Trade-off: between the failed execution and the EXPIRE firing, the scope is
// blocked. With default ttl=86400s (24h) this is unacceptable for hot scopes —
// override --ttl-seconds per-workflow via add-lock-to-workflow.
//
// To upgrade to active cleanup later, replace this body with: Redis EXISTS
// (or GET) at the failed scope's key → If present → Redis DEL.
// Requires scope-discovery: either pass the held scope through your custom
// error-data fields, or iterate `lock-*` keys via the Redis node's `keys`
// operation. Much simpler than the pre-B-16 token-fencing version since the
// lock value is now a plain integer (no JSON.parse + ownership check).
const executionId = $workflow.errorData?.execution?.id || $execution.id;
return [{
  json: {
    cleaned: false,
    reason: 'TTL-bounded cleanup — orphan locks self-heal via Redis-side EXPIRE',
    executionId,
  },
}];
